import sys
import math

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    N = int(data[0])
    if N == 1:
        print(1)
        return

    # max exponent k such that 2^k <= N
    max_k = N.bit_length() - 1

    # Möbius function up to max_k (max_k <= 60 for N <= 1e18)
    mu = [1] * (max_k + 1)
    mu[0] = 0
    primes = []
    is_comp = [False] * (max_k + 1)
    for i in range(2, max_k + 1):
        if not is_comp[i]:
            primes.append(i)
            mu[i] = -1
        for p in primes:
            ip = i * p
            if ip > max_k:
                break
            is_comp[ip] = True
            if i % p == 0:
                mu[ip] = 0
                break
            else:
                mu[ip] = -mu[i]

    # integer k-th root floor(N**(1/k))
    def kth_root(k: int) -> int:
        lo = 1
        log2_N = N.bit_length() - 1
        # upper bound : 2^{ceil(log2_N / k) + 1}
        ub = 1 << ((log2_N + k - 1) // k + 1)
        hi = ub
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if pow(mid, k) <= N:
                lo = mid
            else:
                hi = mid - 1
        return lo

    total = 0

    # k = 2 using integer sqrt
    if max_k >= 2:
        a = math.isqrt(N)
        if a >= 2:
            total += mu[2] * (a - 1)

    # k >= 3
    for k in range(3, max_k + 1):
        if mu[k] == 0:
            continue
        a = kth_root(k)          # a >= 2 because k <= max_k
        total += mu[k] * (a - 1)

    # answer includes 1
    ans = 1 - total
    print(ans)


if __name__ == "__main__":
    solve()

import sys

MOD = 998244353

def solve() -> None:
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    A = [int(next(it)) for _ in range(N)]

    # answer[k] – result for length k   (1‑based)
    answer = [0] * (N + 1)
    answer[1] = N % MOD

    # dp[i] : dict { difference d : { length : count } }
    dp = [dict() for _ in range(N)]

    for i in range(N):
        Ai = A[i]
        for p in range(i):
            d = Ai - A[p]

            # 1) extend subsequences ending at p with the same difference
            prev = dp[p].get(d)
            if prev:
                # prev maps length -> count
                for length, cnt in prev.items():
                    new_len = length + 1
                    cur = dp[i].get(d)
                    if cur is None:
                        dp[i][d] = {new_len: cnt % MOD}
                    else:
                        cur[new_len] = (cur.get(new_len, 0) + cnt) % MOD
                    answer[new_len] = (answer[new_len] + cnt) % MOD

            # 2) start a new subsequence of length 2 : (p , i)
            cur = dp[i].get(d)
            if cur is None:
                dp[i][d] = {2: 1}
            else:
                cur[2] = (cur.get(2, 0) + 1) % MOD
            answer[2] = (answer[2] + 1) % MOD

    # output answers for k = 1 .. N
    out = ' '.join(str(answer[i] % MOD) for i in range(1, N + 1))
    sys.stdout.write(out)


