from typing import List
from collections import deque

class Node:
    __slots__ = ('children', 'fail', 'output', 'word_len', 'cost')
    def __init__(self):
        self.children = {}
        self.fail = None
        self.output = None  # next node in fail chain that has a word
        self.word_len = 0   # 0 means no word ends here
        self.cost = float('inf')

class Solution:
    def minimumCost(self, target: str, words: List[str], costs: List[int]) -> int:
        # Build Trie with words
        root = Node()
        for w, c in zip(words, costs):
            node = root
            for ch in w:
                if ch not in node.children:
                    node.children[ch] = Node()
                node = node.children[ch]
            # Keep minimum cost for each unique word
            if c < node.cost:
                node.cost = c
                node.word_len = len(w)

        # Build Aho-Corasick failure links using BFS
        queue = deque()
        root.fail = root
        root.output = None

        # Initialize depth 1 nodes
        for ch, node in root.children.items():
            node.fail = root
            node.output = None
            queue.append(node)

        while queue:
            r = queue.popleft()
            for ch, u in r.children.items():
                # Compute failure link for u
                p = r.fail
                while p is not root and ch not in p.children:
                    p = p.fail

                if ch in p.children:
                    u.fail = p.children[ch]
                else:
                    u.fail = root

                # Set output link (next word in failure chain)
                if u.fail.word_len > 0:
                    u.output = u.fail
                else:
                    u.output = u.fail.output

                queue.append(u)

        n = len(target)
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[0] = 0

        curr = root
        for i in range(n):
            ch = target[i]
            # Automaton transition
            while curr is not root and ch not in curr.children:
                curr = curr.fail

            if ch in curr.children:
                curr = curr.children[ch]
            else:
                curr = root

            # Check all words ending at position i
            temp = curr
            while temp is not root:
                if temp.word_len > 0:
                    start_idx = i + 1 - temp.word_len
                    if dp[start_idx] != INF:
                        new_cost = dp[start_idx] + temp.cost
                        if new_cost < dp[i + 1]:
                            dp[i + 1] = new_cost
                temp = temp.output

        return dp[n] if dp[n] != INF else -1

class Solution:
    def getSmallestString(self, s: str) -> str:
        chars = list(s)
        n = len(s)

        for i in range(n - 1):
            # Check if both digits have the same parity (both odd or both even)
            if (int(chars[i]) % 2) == (int(chars[i+1]) % 2):
                # Check if swapping makes the string lexicographically smaller
                if chars[i+1] < chars[i]:
                    # Perform the swap
                    chars[i], chars[i+1] = chars[i+1], chars[i]
                    return ''.join(chars)

        # If no beneficial swap found, return the original string
        return s

class Solution:
    def minChanges(self, n: int, k: int) -> int:
        # Check if k has any bit set that is not set in n
        # If so, it's impossible to create that 1 in n (since we can only turn 1s to 0s)
        if (k & ~n) != 0:
            return -1

        # The differing bits are exactly where n is 1 and k is 0
        # We need to change all these 1s to 0s in n
        return (n ^ k).bit_count()

class Solution:
    def doesAliceWin(self, s: str) -> bool:
        """
        Returns True if Alice wins the described game.
        Alice wins exactly when the string contains at least one vowel.
        """
        vowels = set('aeiou')
        # Check whether any character is a vowel
        return any(ch in vowels for ch in s)

import math

class Solution:
    def nonSpecialCount(self, l: int, r: int) -> int:
        total = r - l + 1
        # Calculate the range for prime p such that p^2 is in [l, r]
        # ceil(sqrt(l)) = floor(sqrt(l-1)) + 1
        a = math.isqrt(l - 1) + 1
        # floor(sqrt(r))
        b = math.isqrt(r)

        # If no prime can have p^2 in [l, r], all numbers are non-special
        if a > b:
            return total

        # Sieve of Eratosthenes to find primes up to b
        # b is at most sqrt(10^9) < 32000
        is_prime = [True] * (b + 1)
        if b >= 0:
            is_prime[0] = False
        if b >= 1:
            is_prime[1] = False

        for i in range(2, int(math.isqrt(b)) + 1):
            if is_prime[i]:
                for j in range(i * i, b + 1, i):
                    is_prime[j] = False

        # Count special numbers: primes p where a <= p <= b
        special_count = sum(is_prime[a:b+1])

        return total - special_count

import math

class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        n = len(s)
        # Maximum number of zeros possible in a valid substring
        # If zeros > sqrt(n), then zeros^2 > n >= ones + zeros > ones, so condition fails
        max_zeros = int(math.isqrt(n))
        ans = 0

        for i in range(n):
            zeros = 0
            ones = 0
            for j in range(i, n):
                if s[j] == '0':
                    zeros += 1
                    # Early termination: if zeros exceeds sqrt(n), 
                    # zeros^2 will definitely be larger than any possible count of ones
                    if zeros > max_zeros:
                        break
                else:
                    ones += 1

                # Check dominant condition: ones >= zeros^2
                if ones >= zeros * zeros:
                    ans += 1

        return ans

