class Solution:
    def numberOfAlternatingGroups(self, colors: List[int]) -> int:
        n = len(colors)
        count = 0

        for i in range(n):
            left = (i - 1 + n) % n
            right = (i + 1) % n

            # Check if current tile is different from both neighbors
            if colors[i] != colors[left] and colors[i] != colors[right]:
                count += 1

        return count

from typing import List

class Solution:
    def countSubarrays(self, nums: List[int], k: int) -> int:
        res = 0
        # Dictionary to store {and_value: count of subarrays ending at previous index with this and_value}
        curr = {}

        for num in nums:
            nxt = {}
            # Start new subarray at current index
            nxt[num] = 1

            # Extend all subarrays from the previous step
            for val, cnt in curr.items():
                new_val = val & num
                nxt[new_val] = nxt.get(new_val, 0) + cnt

            # Add count of subarrays ending at current index with AND equal to k
            res += nxt.get(k, 0)
            curr = nxt

        return res

