class Solution:
    def minimumLength(self, s: str) -> int:
        from collections import Counter

        # Count frequency of each character
        freq = Counter(s)

        res = 0
        for count in freq.values():
            if count > 0:
                # If frequency is odd, we can reduce it to 1
                # If frequency is even, we can reduce it to 2
                res += 1 if count % 2 == 1 else 2

        return res

