from typing import List

class Solution:
    def timeTaken(self, edges: List[List[int]]) -> List[int]:
        n = len(edges) + 1
        # weight of each vertex
        w = [2 if i % 2 == 0 else 1 for i in range(n)]

        g = [[] for _ in range(n)]
        for u, v in edges:
            g[u].append(v)
            g[v].append(u)

        # ---------- build parent array and order (iterative DFS) ----------
        parent = [-1] * n
        order = []
        stack = [0]
        parent[0] = -1          # root has no parent
        while stack:
            u = stack.pop()
            order.append(u)
            for v in g[u]:
                if v == parent[u]:
                    continue
                parent[v] = u
                stack.append(v)

        # ---------- down[u] : best sum inside the subtree of u ----------
        down = [0] * n
        for u in reversed(order):
            best_child = 0
            for v in g[u]:
                if v == parent[u]:
                    continue
                if down[v] > best_child:
                    best_child = down[v]
            down[u] = w[u] + best_child

        # ---------- up[u] : dp[u -> parent] ----------
        up = [0] * n            # up[0] stays 0 (no parent side)

        for u in order:
            # find the two largest values among the neighbours of u
            best1 = -1          # largest
            best2 = -1          # second largest
            best1_nb = -1       # neighbour that gives best1

            for v in g[u]:
                if v == parent[u]:
                    val = up[u]          # direction to the parent side
                else:
                    val = down[v]        # direction to the child side

                if val > best1:
                    best2 = best1
                    best1 = val
                    best1_nb = v
                elif val > best2:
                    best2 = val

            if best2 < 0:
                best2 = 0

            # propagate to children
            for v in g[u]:
                if v == parent[u]:
                    continue
                # the best neighbour of u that is not v
                cand = best1 if best1_nb != v else best2
                up[v] = w[u] + cand

        # ---------- answer for every vertex ----------
        ans = [0] * n
        for u in range(n):
            best = 0
            # parent side
            if parent[u] != -1:
                best = max(best, up[u])
            # children sides
            for v in g[u]:
                if v == parent[u]:
                    continue
                best = max(best, down[v])
            ans[u] = best

        return ans

import sys

def solve() -> None:
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    K = int(next(it))

    items = []
    for _ in range(N):
        a = int(next(it))
        b = int(next(it))
        items.append((a, b))

    # sort by decreasing B/(A-1).  A==1 first (key = +inf).
    # we use a tuple (primary, secondary) with ascending order:
    #   primary = 0 if A==1 else 1    -> A==1 come first
    #   secondary = -B/(A-1)           -> larger ratio => smaller secondary
    def sort_key(item):
        a, b = item
        if a == 1:
            return (0, 0.0)          # any secondary works, they are equal
        else:
            return (1, - b / (a - 1))

    items.sort(key=sort_key)

    # dp[t] = best value using exactly t functions, -1 means unreachable
    dp = [-1] * (K + 1)
    dp[0] = 1

    # 0/1 knapsack style DP, K is tiny
    for a, b in items:
        # iterate backwards so each item is used at most once
        for t in range(K - 1, -1, -1):
            cur = dp[t]
            if cur < 0:
                continue
            val = cur * a + b
            if val > dp[t + 1]:
                dp[t + 1] = val

    print(dp[K])

if __name__ == "__main__":
    solve()

