import sys

INF = 10 ** 18


def mul_cap(a: int, b: int) -> int:
    """return a*b capped by INF, a,b >= 0"""
    if a == 0 or b == 0:
        return 0
    if a > INF // b:
        return INF
    return a * b


def add_cap(a: int, b: int) -> int:
    s = a + b
    return s if s <= INF else INF


def merge_hull(left, right):
    """combine two intervals, left processed before right"""
    # Cartesian product of lines
    lines = []
    for pl, cl in left:
        for pr, cr in right:
            p = mul_cap(pl, pr)
            c = add_cap(mul_cap(cl, pr), cr)
            lines.append((p, c))

    # sort by slope, keep best intercept for equal slope
    lines.sort(key=lambda x: x[0])
    uniq = []
    for p, c in lines:
        if uniq and p == uniq[-1][0]:
            if c > uniq[-1][1]:
                uniq[-1] = (p, c)
        else:
            uniq.append((p, c))

    # build upper convex hull (max)
    hull = []
    for p, c in uniq:
        while len(hull) >= 2:
            p1, c1 = hull[-2]
            p2, c2 = hull[-1]
            # intersection(p1,c1)-(p2,c2) >= intersection(p2,c2)-(p,c)  ?
            if (c1 - c2) * (p - p2) >= (c2 - c) * (p2 - p1):
                hull.pop()
            else:
                break
        hull.append((p, c))
    return hull


def apply_hull(hull, x):
    """max_{(p,c) in hull} (p*x + c)   (capped by INF)"""
    if x == 0:
        # only intercepts matter
        best = 0
        for p, c in hull:
            if c > best:
                best = c
        return best
    best = 0
    for p, c in hull:
        if p > INF // x:
            val = INF
        else:
            val = p * x + c
            if val > INF:
                val = INF
        if val > best:
            best = val
    return best


class SegTree:
    def __init__(self, A, B):
        self.n = len(A)
        self.A = A
        self.B = B
        self.tree = [None] * (4 * self.n)
        self._build(1, 0, self.n - 1)

    def _build(self, node, l, r):
        if l == r:
            a = self.A[l]
            b = self.B[l]
            if b == 1:
                self.tree[node] = [(1, a)]
            else:
                self.tree[node] = [(1, a), (b, 0)]
            return
        m = (l + r) // 2
        self._build(node * 2, l, m)
        self._build(node * 2 + 1, m + 1, r)
        self.tree[node] = merge_hull(self.tree[node * 2], self.tree[node * 2 + 1])

    def _update(self, node, l, r, idx, a, b):
        if l == r:
            if b == 1:
                self.tree[node] = [(1, a)]
            else:
                self.tree[node] = [(1, a), (b, 0)]
            return
        m = (l + r) // 2
        if idx <= m:
            self._update(node * 2, l, m, idx, a, b)
        else:
            self._update(node * 2 + 1, m + 1, r, idx, a, b)
        self.tree[node] = merge_hull(self.tree[node * 2], self.tree[node * 2 + 1])

    def update(self, idx, a, b):
        self._update(1, 0, self.n - 1, idx, a, b)

    def query(self, ql, qr):
        return self._query(1, 0, self.n - 1, ql, qr, 0)

    def _query(self, node, l, r, ql, qr, v):
        if ql <= l and r <= qr:
            return apply_hull(self.tree[node], v)
        m = (l + r) // 2
        if qr <= m:
            return self._query(node * 2, l, m, ql, qr, v)
        if ql > m:
            return self._query(node * 2 + 1, m + 1, r, ql, qr, v)
        # split: left part first
        v2 = self._query(node * 2, l, m, ql, m, v)
        return self._query(node * 2 + 1, m + 1, r, m + 1, qr, v2)


def solve() -> None:
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    n = int(next(it))
    A = [int(next(it)) for _ in range(n)]
    B = [int(next(it)) for _ in range(n)]
    seg = SegTree(A, B)

    q = int(next(it))
    out = []
    for _ in range(q):
        typ = int(next(it))
        if typ == 1:
            i = int(next(it)) - 1
            x = int(next(it))
            A[i] = x
            seg.update(i, A[i], B[i])
        elif typ == 2:
            i = int(next(it)) - 1
            x = int(next(it))
            B[i] = x
            seg.update(i, A[i], B[i])
        else:               # typ == 3
            l = int(next(it)) - 1
            r = int(next(it)) - 1
            out.append(str(seg.query(l, r)))
