class Solution:
    def countPairs(self, nums: List[int]) -> int:
        n = len(nums)
        count = 0

        for i in range(n):
            for j in range(i + 1, n):
                if self.isAlmostEqual(nums[i], nums[j]):
                    count += 1
        return count

    def isAlmostEqual(self, x: int, y: int) -> bool:
        s1 = str(x)
        s2 = str(y)

        # Pad with leading zeros to make lengths equal
        max_len = max(len(s1), len(s2))
        s1 = s1.zfill(max_len)
        s2 = s2.zfill(max_len)

        # Find positions where digits differ
        diff = []
        for i in range(max_len):
            if s1[i] != s2[i]:
                diff.append(i)
                # If more than 2 differences, we need more than one swap
                if len(diff) > 2:
                    return False

        # If no differences, they are equal (0 swaps needed)
        if len(diff) == 0:
            return True

        # If exactly 2 differences, check if swapping would make them equal
        if len(diff) == 2:
            i, j = diff
            # Check if swapping s1[i] and s1[j] would make s1 equal to s2
            # This happens if s1[i] == s2[j] and s1[j] == s2[i]
            return s1[i] == s2[j] and s1[j] == s2[i]

        # If 1 difference or any other case, one swap is not sufficient
        return False

