class Solution:
    def maxScore(self, grid: List[List[int]]) -> int:
        n = len(grid)

        # Map each value to the set of rows that contain it
        value_to_rows = {}
        for r in range(n):
            for val in grid[r]:
                if val not in value_to_rows:
                    value_to_rows[val] = set()
                value_to_rows[val].add(r)

        # dp[mask] represents the maximum score achievable using the subset of rows 
        # indicated by bitmask mask (1 means row is already used)
        dp = [-1] * (1 << n)
        dp[0] = 0

        # For each unique value, try to assign it to an available row that contains it
        for v, rows in value_to_rows.items():
            rows = list(rows)
            # Iterate backwards to ensure each value is used at most once (0/1 knapsack style)
            for mask in range((1 << n) - 1, -1, -1):
                if dp[mask] < 0:
                    continue
                for r in rows:
                    if not (mask >> r) & 1:  # row r is not yet used
                        new_mask = mask | (1 << r)
                        dp[new_mask] = max(dp[new_mask], dp[mask] + v)

        return max(dp)

