class Solution:
    def maximumSubarrayXor(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        n = len(nums)
        # Use array('I') to store unsigned 32-bit integers for memory efficiency
        # score[l][r] stores the XOR score of subarray nums[l..r]
        score = [array('I', [0]) * n for _ in range(n)]
        # dp[l][r] stores the maximum XOR score of any subarray within nums[l..r]
        dp = [array('I', [0]) * n for _ in range(n)]

        for length in range(1, n + 1):
            for l in range(0, n - length + 1):
                r = l + length - 1
                if length == 1:
                    val = nums[l]
                else:
                    # Lowest set bit of (length-1)
                    v = (length - 1) & -(length - 1)
                    val = score[l][r - v] ^ score[l + v][r]
                score[l][r] = val

                if length == 1:
                    dp[l][r] = val
                else:
                    # Maximum of: current subarray, best in [l, r-1], best in [l+1, r]
                    best = val
                    if dp[l][r - 1] > best:
                        best = dp[l][r - 1]
                    if dp[l + 1][r] > best:
                        best = dp[l + 1][r]
                    dp[l][r] = best

        return [dp[l][r] for l, r in queries]

