from typing import List

class Solution:
    def findMaximumScore(self, nums: List[int]) -> int:
        n = len(nums)
        if n <= 1:
            return 0

        # Line: y = m*x + b
        class Line:
            __slots__ = ('m', 'b')
            def __init__(self, m: int, b: int):
                self.m = m
                self.b = b
            def eval(self, x: int) -> int:
                return self.m * x + self.b

        # Li Chao Tree for maximum
        class LiChao:
            __slots__ = ('l', 'r', 'left', 'right', 'line')
            def __init__(self, l: int, r: int):
                self.l = l
                self.r = r
                self.left = None
                self.right = None
                self.line = None

            def insert(self, new_line: Line):
                l, r = self.l, self.r
                if self.line is None:
                    self.line = new_line
                    return

                mid = (l + r) // 2

                # At mid, keep the line with higher value
                if new_line.eval(mid) > self.line.eval(mid):
                    self.line, new_line = new_line, self.line

                if l == r:
                    return

                # Current line is better at mid
                # Check if new_line is better at left or right endpoint
                if new_line.eval(l) > self.line.eval(l):
                    # Better on left side
                    if self.left is None:
                        self.left = LiChao(l, mid)
                    self.left.insert(new_line)
                elif new_line.eval(r) > self.line.eval(r):
                    # Better on right side
                    if self.right is None:
                        self.right = LiChao(mid + 1, r)
                    self.right.insert(new_line)
                # Else: new_line is worse everywhere, discard

            def query(self, x: int) -> int:
                res = float('-inf') if self.line is None else self.line.eval(x)
                if self.l == self.r:
                    return res
                mid = (self.l + self.r) // 2
                if x <= mid and self.left:
                    return max(res, self.left.query(x))
                elif x > mid and self.right:
                    return max(res, self.right.query(x))
                return res

        tree = LiChao(0, n - 1)
        # Line for index 0: dp[0] = 0, so intercept = 0 - 0*nums[0] = 0
        tree.insert(Line(nums[0], 0))

        dp_i = 0
        for i in range(1, n):
            dp_i = tree.query(i)
            # Add line for current index: y = nums[i]*x + (dp[i] - i*nums[i])
            intercept = dp_i - i * nums[i]
            tree.insert(Line(nums[i], intercept))

        return dp_i

