class Solution:
    def resultsArray(self, nums: List[int], k: int) -> List[int]:
        n = len(nums)
        results = []

        # Track the length of consecutive increasing sequence ending at current index
        curr_streak = 1

        # Handle the first element separately when k == 1
        if k == 1:
            results.append(nums[0])

        for i in range(1, n):
            # Check if current element continues a consecutive sequence (diff exactly 1)
            if nums[i] == nums[i - 1] + 1:
                curr_streak += 1
            else:
                curr_streak = 1

            # If we have processed at least k elements, check the window ending at i
            if i >= k - 1:
                if curr_streak >= k:
                    results.append(nums[i])
                else:
                    results.append(-1)

        return results

class Solution:
    def maximumValueSum(self, board: List[List[int]]) -> int:
        m = len(board)
        n = len(board[0])

        # Optimization: iterate over the smaller dimension for row triples
        if m > n:
            # Transpose the board
            board = list(zip(*board))
            m, n = n, m

        # Precompute top 3 (value, column) pairs for each row
        # Since we place 3 rooks, in an optimal solution, each rook must be placed 
        # in one of the top 3 cells of its row (otherwise we could move it to a better 
        # free column since only 2 columns are blocked by other rooks)
        top = []
        for i in range(m):
            row_vals = [(board[i][j], j) for j in range(n)]
            row_vals.sort(reverse=True)
            top.append(row_vals[:3])

        ans = -10**18

        # Try all combinations of 3 distinct rows
        for i in range(m):
            for j in range(i + 1, m):
                for k in range(j + 1, m):
                    # Try all 3x3x3 combinations from the top 3 of each row
                    for v1, c1 in top[i]:
                        for v2, c2 in top[j]:
                            if c2 == c1:
                                continue
                            for v3, c3 in top[k]:
                                if c3 != c1 and c3 != c2:
                                    ans = max(ans, v1 + v2 + v3)

        return ans

class Solution:
    def generateKey(self, num1: int, num2: int, num3: int) -> int:
        # Convert to 4-digit strings with leading zeros
        s1 = str(num1).zfill(4)
        s2 = str(num2).zfill(4)
        s3 = str(num3).zfill(4)

        # Build key by taking minimum digit at each position
        key_str = ''.join(min(s1[i], s2[i], s3[i]) for i in range(4))

        # Convert to integer to remove leading zeros
        return int(key_str)

