import bisect

class Solution:
    def maxPathLength(self, coordinates: List[List[int]], k: int) -> int:
        target_x, target_y = coordinates[k]

        left_points = []   # Points with x < target_x and y < target_y
        right_points = []  # Points with x > target_x and y > target_y

        for x, y in coordinates:
            if x < target_x and y < target_y:
                left_points.append((x, y))
            elif x > target_x and y > target_y:
                right_points.append((x, y))

        def longest_increasing_sequence(points):
            """
            Find length of LIS for points where both coordinates strictly increase.
            Sort by x ascending, and for equal x, sort by y descending to handle 
            same-x cases correctly (cannot pick two points with same x).
            """
            # Sort by x ascending, y descending
            points.sort(key=lambda p: (p[0], -p[1]))

            # Patience sorting on y-coordinate to find LIS length
            tails = []
            for x, y in points:
                idx = bisect.bisect_left(tails, y)
                if idx == len(tails):
                    tails.append(y)
                else:
                    tails[idx] = y
            return len(tails)

        left_len = longest_increasing_sequence(left_points)
        right_len = longest_increasing_sequence(right_points)

        # 1 is for the point coordinates[k] itself
        return 1 + left_len + right_len

