class Solution:
    def kthCharacter(self, k: int) -> str:
        word = "a"
        while len(word) < k:
            next_chars = []
            for c in word:
                # Shift character to next in alphabet: 'a'->'b', ..., 'z'->'a'
                next_char = chr((ord(c) - ord('a') + 1) % 26 + ord('a'))
                next_chars.append(next_char)
            word += "".join(next_chars)
        return word[k - 1]

class Solution:
    def countOfSubstrings(self, word: str, k: int) -> int:
        """
        Returns the number of substrings that contain all five vowels at least once
        and exactly k consonants.
        """
        # map each vowel to a distinct bit: a,e,i,o,u -> 1,2,4,8,16
        vowel_bit = {'a': 1, 'e': 2, 'i': 4, 'o': 8, 'u': 16}
        target_mask = (1 << 5) - 1          # 0b11111 = 31
        n = len(word)
        answer = 0
        min_len = 5 + k                    # minimal possible length of a valid substring

        for left in range(n):
            # not enough characters left to ever reach the required length
            if n - left < min_len:
                break

            mask = 0        # which vowels have been seen
            cons = 0        # number of consonants in the current window

            for right in range(left, n):
                bit = vowel_bit.get(word[right], 0)
                if bit:
                    mask |= bit
                else:
                    cons += 1
                    if cons > k:          # further extension can only increase cons
                        break

                # check whether the current window is valid
                if cons == k and mask == target_mask:
                    answer += 1

        return answer

class Solution:
    def minElement(self, nums: List[int]) -> int:
        min_sum = float('inf')

        for num in nums:
            digit_sum = 0
            n = num
            while n > 0:
                digit_sum += n % 10
                n //= 10
            min_sum = min(min_sum, digit_sum)

        return min_sum

