def solve() -> None:
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    edges_raw = []
    used = [False] * 26
    for _ in range(N):
        s = next(it)
        u = ord(s[0]) - 65
        v = ord(s[1]) - 65
        edges_raw.append((u, v))
        used[u] = True
        used[v] = True

    # ---------- SCC (Kosaraju) ----------
    g = [[] for _ in range(26)]
    gr = [[] for _ in range(26)]
    for u, v in edges_raw:
        g[u].append(v)
        gr[v].append(u)

    visited = [False] * 26
    order = []

    def dfs1(x: int):
        visited[x] = True
        for to in g[x]:
            if not visited[to]:
                dfs1(to)
        order.append(x)

    for v in range(26):
        if used[v] and not visited[v]:
            dfs1(v)

    comp = [-1] * 26
    comp_cnt = 0

    def dfs2(x: int, label: int):
        comp[x] = label
        for to in gr[x]:
            if comp[to] == -1:
                dfs2(to, label)

    for v in reversed(order):
        if comp[v] == -1:
            dfs2(v, comp_cnt)
            comp_cnt += 1

    M = comp_cnt                     # number of SCCs
    internal = [0] * M
    has_inter = [False] * M
    inter_edges = []                 # list of (s, t) with s != t

    for u, v in edges_raw:
        cu = comp[u]
        cv = comp[v]
        if cu == cv:
            internal[cu] += 1
        else:
            inter_edges.append((cu, cv))
            has_inter[cu] = True
            has_inter[cv] = True

    isolated_internal = 0
    for c in range(M):
        if internal[c] > 0 and not has_inter[c]:
            isolated_internal += 1

    K = len(inter_edges)
    if K == 0:
        # only internal edges, one string per isolated component
        print(isolated_internal)
        return

    # ---------- transitive closure of the condensation ----------
    # reach[x] is a bitset of vertices reachable from x
    reach = [0] * M
    for i in range(M):
        reach[i] = 1 << i
    for s, t in inter_edges:
        reach[s] |= 1 << t

    for k in range(M):
        rk = reach[k]
        for i in range(M):
            if (reach[i] >> k) & 1:
                reach[i] |= rk

    # ---------- bipartite graph (left = edges, right = edges) ----------
    adj = [[] for _ in range(K)]
    for i in range(K):
        ti = inter_edges[i][1]          # head component of edge i
        mask = reach[ti]
        for j in range(K):
            if i == j:
                continue
            sj = inter_edges[j][0]      # tail component of edge j
            if (mask >> sj) & 1:
                adj[i].append(j)

    # ---------- maximum matching (Kuhn) ----------
    match_r = [-1] * K   # right vertex -> left vertex

    def dfs(v: int, seen: list) -> bool:
        for u in adj[v]:
            if seen[u]:
                continue
            seen[u] = True
            if match_r[u] == -1 or dfs(match_r[u], seen):
                match_r[u] = v
                return True
        return False

    matching = 0
    for v in range(K):
        seen = [False] * K
        if dfs(v, seen):
            matching += 1

    path_cover = K - matching
    answer = path_cover + isolated_internal
    print(answer)


