import sys

INF = 10 ** 9


def l1_distance_transform(arr):
    """arr : list of length N (index 0 unused)
       returns res where res[i] = min_j (arr[j] + |i-j|)   for i=1..N-1"""
    n = len(arr)
    res = [INF] * n
    # left to right
    cur = INF
    for i in range(1, n):
        # cur = min(arr[i], cur+1)
        if arr[i] < cur + 1:
            cur = arr[i]
        else:
            cur = cur + 1
        res[i] = cur
    # right to left
    cur = INF
    for i in range(n - 1, 0, -1):
        if arr[i] < cur + 1:
            cur = arr[i]
        else:
            cur = cur + 1
        if cur < res[i]:
            res[i] = cur
        else:
            pass
    return res


def trans_LL(a, b, dp, N):
    """left hand moves from a to b, dp[w] – cost before, result after"""
    D = (b - a) % N
    if D == 0:
        return l1_distance_transform(dp)

    # clockwise walk (D steps)
    h = [INF] * N
    limit = D - 1
    for x in range(1, N):
        pos = x - D
        if pos < 1:
            pos = 1
        val = dp[x] + max(0, D + 1 - x)
        if val < h[pos]:
            h[pos] = val
    g = l1_distance_transform(h)
    cost_cw = [INF] * N
    for y in range(1, N):
        cost_cw[y] = D + g[y]

    # counter‑clockwise walk (N-D steps)
    D2 = N - D
    h2 = [INF] * N
    for x in range(1, N):
        pos = x + D2
        if pos > N - 1:
            pos = N - 1
        val = dp[x] + max(0, x - limit)
        if val < h2[pos]:
            h2[pos] = val
    g2 = l1_distance_transform(h2)
    cost_ccw = [INF] * N
    for y in range(1, N):
        cost_ccw[y] = D2 + g2[y]

    res = [INF] * N
    for i in range(1, N):
        if cost_cw[i] < cost_ccw[i]:
            res[i] = cost_cw[i]
        else:
            res[i] = cost_ccw[i]
    return res


def trans_LR(a, b, dp, N):
    """left hand fixed at a, right hand fixed at b, dp[w] – before, result after"""
    C = (b - a) % N
    f = dp

    # prefix minimum of f[x] - x
    pre_minus = [INF] * N
    best = INF
    for i in range(1, N):
        val = f[i] - i
        if val < best:
            best = val
        pre_minus[i] = best

    # suffix minimum of f[x] + x
    suf_plus = [INF] * (N + 2)
    best = INF
    for i in range(N - 1, 0, -1):
        val = f[i] + i
        if val < best:
            best = val
        suf_plus[i] = best
    # suf_plus[0] is never used, but for safety
    suf_plus[0] = suf_plus[1]

    # suffix minima for s = C and s = C+N
    s_vals = (C, C + N)
    suf_s = {}
    for s in s_vals:
        arr = [INF] * (N + 2)
        best = INF
        for i in range(N - 1, 0, -1):
            val = f[i] + abs(s - i)
            if val < best:
                best = val
            arr[i] = best
        suf_s[s] = arr

    # prefix minima for s = C and s = C-N
    sp_vals = (C, C - N)
    pre_sp = {}
    for s in sp_vals:
        arr = [INF] * (N + 2)
        best = INF
        for i in range(1, N):
            val = f[i] + abs(s - i)
            if val < best:
                best = val
            arr[i] = best
        pre_sp[s] = arr

    res = [INF] * N
    for y in range(1, N):
        # which regime ?
        if C > 0 and y <= C:
            d = C - y          # 0 .. C-1
            s = C
            sp = C - N
        else:
            d = C - y + N      # N+C-y
            s = C + N
            sp = C

        # ----- clockwise (left hand walks clockwise) -----
        Lbound = d + 1
        if Lbound <= N - 1:
            term1 = suf_s[s][Lbound]
        else:
            term1 = INF
        idx = d + 1
        if idx > N - 1:
            idx = N - 1
        term2 = s + pre_minus[idx]
        cand_cw = d + (term1 if term1 < term2 else term2)

        # ----- counter‑clockwise -----
        d2 = N - d
        # part using prefix (x <= d-1)
        if d - 1 >= 1:
            term1_ccw = d2 + pre_sp[sp][d - 1]
        else:
            term1_ccw = INF
        # part using suffix (x >= d)
        if d <= N - 1:
            if d == 0:
                spv = suf_plus[1]
            else:
                spv = suf_plus[d]
        else:
            spv = INF
        term2_ccw = 2 * d2 - y + spv
        cand_ccw = term1_ccw if term1_ccw < term2_ccw else term2_ccw

        # best of the two directions
        val = cand_cw if cand_cw < cand_ccw else cand_ccw
        res[y] = val
    return res


def transform_w(arr, N):
    """w -> N-w  (swap left and right)"""
    res = [INF] * N
    for w in range(1, N):
        res[w] = arr[N - w]
    return res


def transition(prev_hand, prev_pos, next_hand, next_pos, dp, N):
    """return new dp array after following one instruction"""
    if prev_hand == next_hand:
        if prev_hand == 0:          # L -> L
            return trans_LL(prev_pos, next_pos, dp, N)
        else:                       # R -> R  (swap w)
            sw = transform_w(dp, N)
            sw = trans_LL(prev_pos, next_pos, sw, N)
            return transform_w(sw, N)
    else:
        if prev_hand == 0 and next_hand == 1:
            # L -> R
            return trans_LR(prev_pos, next_pos, dp, N)
        else:
            # R -> L  (swap w, call LR, swap back)
            sw = transform_w(dp, N)
            sw = trans_LR(prev_pos, next_pos, sw, N)
            return transform_w(sw, N)


def solve() -> None:
    it = iter(sys.stdin.read().strip().split())
    N = int(next(it))
    Q = int(next(it))
    instr = []
    for _ in range(Q):
        h = next(it)
        t = int(next(it)) - 1          # 0‑based
        instr.append((0 if h == 'L' else 1, t))

    # initial state: left hand on 0, right hand on 1  → w = 1
    dp = [INF] * N
    dp[1] = 0
    fixed_hand = 0          # left hand is fixed before any instruction
    fixed_pos = 0

    for h, t in instr:
        dp = transition(fixed_hand, fixed_pos, h, t, dp, N)
        fixed_hand = h
        fixed_pos = t

    ans = min(dp[1:])       # w is never 0
    print(ans)


