from sys import stdin

def solve():
    input = sys.stdin.buffer.read().split()
    idx = 0
    N = int(input[idx]); idx += 1
    M = int(input[idx]); idx += 1

    R = set()
    C = set()
    S = set()  # sums
    D = set()  # diffs

    for _ in range(M):
        a = int(input[idx]); b = int(input[idx+1]); idx += 2
        R.add(a)
        C.add(b)
        S.add(a + b)
        D.add(a - b)

    # Precompute lengths of diagonals
    def len_sum(s):
        if s <= N + 1:
            return s - 1
        else:
            return 2 * N - s + 1

    def len_diff(d):
        return N - abs(d)

    # Total sum of lengths of all attack lines
    total = len(R) * N + len(C) * N
    for s in S:
        total += len_sum(s)
    for d in D:
        total += len_diff(d)

    SHIFT = 30
    MASK = (1 << SHIFT) - 1
    points_set = set()

    # Helper to add point
    def add_point(r, c):
        if 1 <= r <= N and 1 <= c <= N:
            key = (r << SHIFT) | c
            points_set.add(key)

    # 1. Row - Col
    for r in R:
        for c in C:
            add_point(r, c)

    # 2. Row - Sum
    for r in R:
        for s in S:
            c = s - r
            add_point(r, c)

    # 3. Row - Diff
    for r in R:
        for d in D:
            c = r - d
            add_point(r, c)

    # 4. Col - Sum
    for c in C:
        for s in S:
            r = s - c
            add_point(r, c)

    # 5. Col - Diff
    for c in C:
        for d in D:
            r = c + d
            add_point(r, c)

    # 6. Sum - Diff
    for s in S:
        for d in D:
            if (s + d) & 1:
                continue
            r = (s + d) // 2
            c = (s - d) // 2
            add_point(r, c)

    # Compute correction: sum_{P in points} (m_P - 1)
    correction = 0
    # Convert sets to hash sets for O(1) lookup
    R_set = R
    C_set = C
    S_set = S
    D_set = D

    for key in points_set:
        r = key >> SHIFT
        c = key & MASK
        m = 0
        if r in R_set:
            m += 1
        if c in C_set:
            m += 1
        sm = r + c
        if sm in S_set:
            m += 1
        df = r - c
        if df in D_set:
            m += 1
        if m >= 2:
            correction += (m - 1)

    ans = N * N - total + correction
    print(ans)

