    if not data:
        return
    it = iter(data)
    n = int(next(it))
    adj = [[] for _ in range(n + 1)]
    for _ in range(n - 1):
        u = int(next(it))
        v = int(next(it))
        adj[u].append(v)
        adj[v].append(u)

    deg = [0] * (n + 1)
    for v in range(1, n + 1):
        deg[v] = len(adj[v])

    visited = [False] * (n + 1)
    ans = 0

    for v in range(1, n + 1):
        if deg[v] != 3 or visited[v]:
            continue

        # explore one component of degree-3 vertices
        stack = [v]
        visited[v] = True
        cnt = 0                      # |S(C)|

        while stack:
            u = stack.pop()
            for w in adj[u]:
                if deg[w] == 3:
                    if not visited[w]:
                        visited[w] = True
                        stack.append(w)
                elif deg[w] == 2:
                    # neighbour belongs to S(C)
                    cnt += 1

        ans += cnt * (cnt - 1) // 2

    sys.stdout.write(str(ans))

