import sys
sys.setrecursionlimit(10000)

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    A = int(data[0])
    B = int(data[1])
    MOD = int(data[2])

    # ------------------------------------------------------------
    # hook-length formula: number of SYT of a diagram given by row lengths
    from functools import lru_cache

    @lru_cache(maxsize=None)
    def hook_count(rows):
        """rows : tuple of non-increasing row lengths, 0 may be omitted"""
        n = sum(rows)
        if n == 0:
            return 1
        # product of hook lengths
        prod = 1
        a = len(rows)
        for i, row in enumerate(rows):
            for j in range(row):
                # arm = row - j - 1
                # leg = number of rows below with length > j
                leg = 0
                for ii in range(i + 1, a):
                    if rows[ii] > j:
                        leg += 1
                    else:
                        break
                hook = (row - j - 1) + leg + 1
                prod = (prod * hook) % MOD
        # n! / prod   ( MOD is prime, n < MOD )
        fact = 1
        for i in range(2, n + 1):
            fact = (fact * i) % MOD
        return fact * pow(prod, MOD - 2, MOD) % MOD

    # ------------------------------------------------------------
    # distribution of the entry in cell (1, c) of the a x b rectangle
    def column_distribution(a, b, c):
        """return list D where D[k] = #{SYT with entry (1,c)=k} (0<=k<=a*b)"""
        target_col = c - 1          # 0‑based column index

        @lru_cache(maxsize=None)
        def dfs(rows):
            """rows is a tuple of row lengths (non‑increasing).
               Returns a dict {value : count} for the entry of the target cell.
               The cell must be present, otherwise empty dict."""
            if rows[0] <= target_col:          # cell not present
                return {}
            n = sum(rows)
            # base: only the target cell exists
            if n == 1:
                return {1: 1}
            res = {}
            # iterate over corners
            for i in range(len(rows)):
                if rows[i] == 0:
                    continue
                # is it a corner? (last row or strictly larger than next row)
                if i + 1 < len(rows) and rows[i] == rows[i + 1]:
                    continue
                # create child shape by removing this corner
                lst = list(rows)
                lst[i] -= 1
                # delete trailing zeros
                while lst and lst[-1] == 0:
                    lst.pop()
                child = tuple(lst)
                child_dist = dfs(child)          # may be empty
                child_f = hook_count(child)      # total number of SYT of child
                if i == 0 and rows[i] - 1 == target_col:
                    # the corner is the target cell
                    for k, cnt in child_dist.items():
                        res[k] = (res.get(k, 0) + cnt) % MOD
                    # the target gets the maximal entry n
                    res[n] = (res.get(n, 0) + child_f) % MOD
                else:
                    for k, cnt in child_dist.items():
                        res[k] = (res.get(k, 0) + cnt) % MOD
            return res

        full = tuple([b] * a)          # a rows, each of length b
        dist_dict = dfs(full)
        size = a * b
        arr = [0] * (size + 1)
        for k, v in dist_dict.items():
            arr[k] = v % MOD
        return arr

    # ------------------------------------------------------------
    # distributions for the two required cells
    D1 = column_distribution(A, B, A)          # column A in A×B
    D2 = column_distribution(B, A, B)          # column B in B×A

    S = A * B
    # suffix sums of D2
    suffix = [0] * (S + 2)
    for k in range(S, 0, -1):
        suffix[k] = (suffix[k + 1] + D2[k]) % MOD

    ans = 0
    for i in range(1, S + 1):
        if D1[i] == 0:
            continue
        need = S + 1 - i          # we need j >= need
        if need <= 1:
            add = suffix[1]
        else:
            add = suffix[need] if need <= S + 1 else 0
        ans = (ans + D1[i] * add) % MOD

    print(ans)


if __name__ == "__main__":
    solve()

