import sys

MOD = 998244353

def solve() -> None:
    it = iter(sys.stdin.read().strip().split())
    H = int(next(it))
    W = int(next(it))
    grid = [list(next(it).strip()) for _ in range(H)]

    # rotate so that W <= H  (W becomes the small dimension, at most 14)
    if W > H:
        # transpose
        grid = [''.join(grid[i][j] for i in range(H)) for j in range(W)]
        H, W = W, H

    # convert characters to numbers: '1'->0, '2'->1, '3'->2, '?']->-1
    fixed = [[-1]*W for _ in range(H)]
    for i in range(H):
        row = grid[i]
        for j,ch in enumerate(row):
            if ch == '?':
                fixed[i][j] = -1
            else:
                fixed[i][j] = ord(ch) - ord('1')   # 0,1,2

    # ------------------------------------------------------------
    # 1. enumerate all valid row patterns (path of length W, 3 colours)
    patterns = []          # list of tuples of length W
    code_to_idx = {}
    cur = [0]*W

    def gen(pos: int, prev: int, code: int):
        if pos == W:
            idx = len(patterns)
            patterns.append(tuple(cur))
            code_to_idx[code] = idx
            return
        for col in range(3):
            if pos > 0 and col == prev:
                continue
            cur[pos] = col
            gen(pos+1, col, code*3 + col)

    gen(0, -1, 0)
    U = len(patterns)               # = 3 * 2^{W-1}

    # ------------------------------------------------------------
    # 2. compatibility lists: pattern p is compatible with q iff they differ in every column
    compat = [[] for _ in range(U)]

    # temporary list to avoid repeated tuple indexing overhead
    for p_idx in range(U):
        cols = patterns[p_idx]
        # depth first search over columns, building the code of q
        def dfs(pos: int, prev_c: int, cur_code: int):
            if pos == W:
                q_idx = code_to_idx[cur_code]
                compat[p_idx].append(q_idx)
                return
            forbidden = cols[pos]
            for col in range(3):
                if col == forbidden:
                    continue
                if pos > 0 and col == prev_c:
                    continue
                dfs(pos+1, col, cur_code*3 + col)
        dfs(0, -1, 0)

    # ------------------------------------------------------------
    # 3. for each grid row compute which patterns are allowed
    allowed_rows = []
    for r in range(H):
        row_fixed = fixed[r]
        allowed = [False]*U
        # check every pattern
        for idx in range(U):
            pat = patterns[idx]
            ok = True
            # early exit on first mismatch
            for c in range(W):
                rf = row_fixed[c]
                if rf != -1 and pat[c] != rf:
                    ok = False
                    break
            if ok:
                allowed[idx] = True
        allowed_rows.append(allowed)

    # ------------------------------------------------------------
    # 4. DP over rows
    dp_prev = [0]*U
    # first row
    for i in range(U):
        if allowed_rows[0][i]:
            dp_prev[i] = 1

    for r in range(1, H):
        allowed_cur = allowed_rows[r]
        dp_cur = [0]*U
        # iterate over all previous patterns (U ≤ 25000)
        for p in range(U):
            val = dp_prev[p]
            if val == 0:
                continue
            # try all compatible patterns
            for q in compat[p]:
                if allowed_cur[q]:
                    new = dp_cur[q] + val
                    if new >= MOD:
                        new -= MOD
                    dp_cur[q] = new
        dp_prev = dp_cur

    # answer: sum over allowed patterns of the last row
    ans = 0
    allowed_last = allowed_rows[H-1]
    for i in range(U):
        if allowed_last[i]:
            ans += dp_prev[i]
            if ans >= MOD:
                ans -= MOD
    print(ans % MOD)


