def solve() -> None:
    data = sys.stdin.read().split()
    if not data:
        return
    S = data[0]
    n = len(S)
    S_flip = S.swapcase()
    Q = int(data[1])
    # read exactly Q integers (the rest may be empty or extra, but we take first Q)
    Ks = list(map(int, data[2:2+Q]))
    out = []
    # helper: parity of popcount of x
    # since x <= 1e18 < 2^60, we can use builtin bit_count if available,
    # otherwise bin(x).count('1') is fast enough.
    if hasattr(int, "bit_count"):
        def popcount_parity(x: int) -> int:
            return x.bit_count() & 1
    else:
        def popcount_parity(x: int) -> int:
            return bin(x).count('1') & 1

    for K in Ks:
        pos = K - 1               # 0-indexed
        block = pos // n          # which block of length n
        idx = pos - block * n     # offset inside the block (same as pos % n)
        if popcount_parity(block) == 0:
            out.append(S[idx])
        else:
            out.append(S_flip[idx])
    sys.stdout.write(' '.join(out))

