        mask = 0
        for j in range(n):
            x2, y2 = floors[j]
            if abs(x1 - x2) + abs(y1 - y2) <= D:
                mask |= (1 << j)
        masks.append(mask)

    max_humid = 0
    for i in range(n):
        for j in range(i + 1, n):
            combined = masks[i] | masks[j]
            # Count number of set bits (humidified floor cells)
            count = bin(combined).count('1')
            if count > max_humid:
                max_humid = count

    print(max_humid)

