import math

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    N = int(data[0])
    M = math.isqrt(N)               # floor(sqrt(N))

    # ---------- sieve of Eratosthenes up to M ----------
    if M >= 2:
        n = M
        sieve = bytearray(b'\x01') * (n + 1)
        sieve[0:2] = b'\x00\x00'
        limit = int(math.isqrt(n))
        for p in range(2, limit + 1):
            if sieve[p]:
                start = p * p
                sieve[start:n+1:p] = b'\x00' * ((n - start) // p + 1)
        primes = [i for i, is_prime in enumerate(sieve) if is_prime]
    else:
        primes = []

    # ---------- count numbers of the form p^8 ----------
    count_p8 = 0
    # 100^8 = 10^16 > max N (4e12), so we need only check primes <= 100
    for p in primes:
        if p > 100:
            break
        if pow(p, 8) <= N:
            count_p8 += 1
        else:
            # since primes are increasing, further primes will be larger
            break

    # ---------- count numbers of the form p^2 * q^2 (p<q) ----------
    # condition: p*q <= M
    ans_pairs = 0
    P = len(primes)
    if P > 0:
        j = P - 1
        for i in range(P):
            p = primes[i]
            # shrink j while product exceeds M
            while j > i and p * primes[j] > M:
                j -= 1
            if j <= i:
                break
            ans_pairs += (j - i)

    total = count_p8 + ans_pairs
    sys.stdout.write(str(total))

