        y = int(next(it))
        c = next(it)               # b'B' or b'W'
        if x not in rows:
            # max_black = 0, min_white = N+1  (meaning "no white")
            rows[x] = [0, N + 1]
        info = rows[x]
        if c == b'B':
            if y > info[0]:
                info[0] = y
        else:  # 'W'
            if y < info[1]:
                info[1] = y

    # build list of (row_index, L, U)
    arr = []
    for r, (bmax, wmin) in rows.items():
        L = bmax                     # lower bound
        U = wmin - 1                 # upper bound (N if no white)
        if L > U:
            print("No")
            return
        arr.append((r, L, U))

    arr.sort(key=lambda x: x[0])

    cur_min = N   # current running minimum of U (M[i] in the proof)
    for _, L, U in arr:
        if U < cur_min:
            cur_min = U
        if L > cur_min:
            print("No")
            return

    print("Yes")


