        return
    it = iter(input_data)
    N = int(next(it))
    Q = int(next(it))
    queries = [int(next(it)) for _ in range(Q)]
    max_val = N * N
    # Precompute all possible K: N^2 - p*q where p,q in {0} U [2,N]
    possible = [False] * (max_val + 1)
    possible[max_val] = True  # p=0 or q=0
    for p in range(2, N + 1):
        for q in range(2, N + 1):
            k = max_val - p * q
            if 0 <= k <= max_val:
                possible[k] = True
    # also K=0 corresponds to p=N,q=N, already covered when p=N,q=N (since N>=2)
    out_lines = []
    for K in queries:
        if 0 <= K <= max_val and possible[K]:
            out_lines.append("Yes")
        else:
            out_lines.append("No")
