import sys

MOD = 998244353

def solve() -> None:
    data = sys.stdin.read().split()
    if not data:
        return
    N = int(data[0])
    K = int(data[1])
    S = data[2].strip()

    # dp[(c0,c1,c2,v)] = number of ways
    # c0,c1,c2 = occurrences of vertices 0,1,2 among the prefixes
    # vertex 3 is implicit: c3 = (current_total) - c0 - c1 - c2
    # v = current vertex (the last prefix)
    dp = {(1, 0, 0, 0): 1}          # start: p0 = 0, visited once

    for i, ch in enumerate(S):
        ndp = {}
        # current number of visited prefixes = i+1
        for (c0, c1, c2, v), ways in dp.items():
            # three possible neighbours
            if ch == '?':
                nbr = [v ^ 1, v ^ 2, 3 - v]
            else:
                if ch == 'A':
                    nbr = [v ^ 1]
                elif ch == 'B':
                    nbr = [v ^ 2]
                else:               # 'C'
                    nbr = [3 - v]

            for u in nbr:
                nc0, nc1, nc2 = c0, c1, c2
                if u == 0:
                    nc0 += 1
                elif u == 1:
                    nc1 += 1
                elif u == 2:
                    nc2 += 1
                # u == 3 : only implicit c3 grows
                key = (nc0, nc1, nc2, u)
                ndp[key] = (ndp.get(key, 0) + ways) % MOD
        dp = ndp

    total_pref = N + 1
    ans = 0
    for (c0, c1, c2, v), ways in dp.items():
        c3 = total_pref - c0 - c1 - c2
        good = (c0 * (c0 - 1) // 2 +
                c1 * (c1 - 1) // 2 +
                c2 * (c2 - 1) // 2 +
                c3 * (c3 - 1) // 2)
        if good >= K:
            ans = (ans + ways) % MOD

    print(ans)


