class Solution:
    def minOperations(self, nums: List[int]) -> int:
        if not nums:
            return 0

        max_val = max(nums)
        spf = self._sieve(max_val)

        # For each number, generate possible (value, cost) pairs
        # Cost is number of operations (0 or 1)
        def get_choices(x):
            if x == 1:
                return [(1, 0)]
            if spf[x] == x:  # x is prime
                return [(x, 0)]
            # x is composite: can keep x (0 ops) or reduce to spf[x] (1 op)
            return [(x, 0), (spf[x], 1)]

        # Initialize DP: map from value to minimum cost to achieve it at index 0
        dp = {}
        for val, cost in get_choices(nums[0]):
            if val not in dp or cost < dp[val]:
                dp[val] = cost

        # Process rest of the array
        for i in range(1, len(nums)):
            curr_choices = get_choices(nums[i])
            new_dp = {}

            for curr_val, curr_cost in curr_choices:
                min_total = float('inf')
                # Check all possible previous values
                for prev_val, prev_cost in dp.items():
                    if prev_val <= curr_val:
                        total = prev_cost + curr_cost
                        if total < min_total:
                            min_total = total

                if min_total != float('inf'):
                    new_dp[curr_val] = min_total

            if not new_dp:
                return -1
            dp = new_dp

        return min(dp.values())

    def _sieve(self, n):
        # Compute smallest prime factor for each number up to n
        spf = [0] * (n + 1)
        if n >= 1:
            spf[1] = 1
        for i in range(2, n + 1):
            if spf[i] == 0:  # i is prime
                spf[i] = i
                if i * i <= n:
                    for j in range(i * i, n + 1, i):
                        if spf[j] == 0:
                            spf[j] = i
        return spf

class Solution:
    def isBalanced(self, num: str) -> bool:
        even_sum = 0
        odd_sum = 0

        for i, c in enumerate(num):
            if i % 2 == 0:
                even_sum += int(c)
            else:
                odd_sum += int(c)

        return even_sum == odd_sum

class Solution:
    def hasIncreasingSubarrays(self, nums: List[int], k: int) -> bool:
        n = len(nums)

        # Helper function to check if subarray starting at idx of length k is strictly increasing
        def is_strictly_increasing(idx: int) -> bool:
            for i in range(idx, idx + k - 1):
                if nums[i] >= nums[i + 1]:
                    return False
            return True

        # Check all valid starting positions for the first subarray
        # The second subarray starts at i + k, so we need i + 2*k <= n
        for i in range(n - 2 * k + 1):
            if is_strictly_increasing(i) and is_strictly_increasing(i + k):
                return True

        return False

