class Solution:
    def countValidSelections(self, nums: List[int]) -> int:
        n = len(nums)
        count = 0

        for i in range(n):
            if nums[i] == 0:
                # Try starting at i moving left
                if self.simulate(nums, i, -1):
                    count += 1
                # Try starting at i moving right
                if self.simulate(nums, i, 1):
                    count += 1

        return count

    def simulate(self, nums: List[int], start: int, direction: int) -> bool:
        # Create a copy of the array to simulate the process
        arr = nums.copy()
        n = len(arr)
        curr = start
        dir = direction

        # Continue while current position is within bounds
        while 0 <= curr < n:
            if arr[curr] == 0:
                # Move in current direction
                curr += dir
            else:
                # Decrement current value
                arr[curr] -= 1
                # Reverse direction
                dir = -dir
                # Move in new direction
                curr += dir

        # Check if all elements became 0
        return all(x == 0 for x in arr)

class Solution:
    def isZeroArray(self, nums: List[int], queries: List[List[int]]) -> bool:
        n = len(nums)
        # Difference array to calculate coverage count for each index
        diff = [0] * (n + 1)

        for l, r in queries:
            diff[l] += 1
            diff[r + 1] -= 1

        # Calculate prefix sum to get the number of queries covering each index
        cover = 0
        for i in range(n):
            cover += diff[i]
            # If any index needs more decrements than available queries covering it, return false
            if nums[i] > cover:
                return False

        return True

