class Solution:
    def minimumSumSubarray(self, nums: List[int], l: int, r: int) -> int:
        n = len(nums)
        # Create prefix sum array where prefix[i] is sum of nums[0..i-1]
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        min_sum = float('inf')

        # Try all subarray lengths from l to r
        for length in range(l, r + 1):
            # Try all starting positions for current length
            for start in range(n - length + 1):
                end = start + length
                current_sum = prefix[end] - prefix[start]

                # Update min_sum if current subarray has positive sum and is smaller
                if current_sum > 0 and current_sum < min_sum:
                    min_sum = current_sum

        return min_sum if min_sum != float('inf') else -1

