class Solution:
    def maximizeSumOfWeights(self, edges: List[List[int]], k: int) -> int:
        sys.setrecursionlimit(300000)
        n = len(edges) + 1
        graph = [[] for _ in range(n)]

        for u, v, w in edges:
            graph[u].append((v, w))
            graph[v].append((u, w))

        def dfs(u, parent):
            total_base = 0
            gains = []

            for v, w in graph[u]:
                if v == parent:
                    continue
                dp0_v, dp1_v = dfs(v, u)
                total_base += dp0_v
                # Gain if we keep edge (u,v) instead of cutting it
                gain = w + dp1_v - dp0_v
                gains.append(gain)

            gains.sort(reverse=True)

            # dp0: parent edge is NOT taken, so we can take up to k children
            dp0 = total_base
            for i in range(min(k, len(gains))):
                if gains[i] > 0:
                    dp0 += gains[i]
                else:
                    break

            # dp1: parent edge IS taken, so we can take up to k-1 children
            dp1 = total_base
            for i in range(min(k - 1, len(gains))):
                if gains[i] > 0:
                    dp1 += gains[i]
                else:
                    break

            return dp0, dp1

        return dfs(0, -1)[0]

