class Solution:
    def minBitwiseArray(self, nums: List[int]) -> List[int]:
        """
        For each odd prime n:
            let low = lowest set bit of (n+1)   # = 2^t where t = ctz(n+1)
            answer = n - (low >> 1)             # n - 2^{t-1}
        For even n (only possible value is 2) answer is -1.
        """
        ans: List[int] = []
        for num in nums:
            if num % 2 == 0:               # only the prime 2 is even
                ans.append(-1)
                continue

            # lowest set bit of num+1  -> 2^t
            low = (num + 1) & -(num + 1)
            # subtract half of it: 2^{t-1}
            ans.append(num - (low >> 1))
        return ans

class Solution:
    def smallestNumber(self, n: int, t: int) -> int:
        def digit_product(x: int) -> int:
            prod = 1
            while x > 0:
                prod *= x % 10
                x //= 10
            return prod

        current = n
        while True:
            if digit_product(current) % t == 0:
                return current
            current += 1

class Solution:
    def canAliceWin(self, n: int) -> bool:
        stones = n
        remove = 10
        isAliceTurn = True

        while stones >= remove:
            stones -= remove
            remove -= 1
            isAliceTurn = not isAliceTurn

        return not isAliceTurn

