class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        # If any element is smaller than k we can never increase it.
        for x in nums:
            if x < k:
                return -1

        # Collect the distinct values that are strictly larger than k.
        # Each distinct value must be "merged" into the next lower one,
        # and finally the smallest of them must be merged into k.
        # One operation is needed per distinct value above k.
        greater = set(x for x in nums if x > k)
        return len(greater)

class Solution:
    def minOperations(self, n: int, m: int) -> int:
        # Sieve of Eratosthenes to check primes up to 9999
        max_num = 10000
        is_prime = [True] * (max_num + 1)
        is_prime[0] = is_prime[1] = False
        for i in range(2, int(max_num**0.5) + 1):
            if is_prime[i]:
                for j in range(i*i, max_num+1, i):
                    is_prime[j] = False

        # If start or end is prime, impossible
        if is_prime[n] or is_prime[m]:
            return -1

        # Get number of digits
        d = len(str(n))

        import heapq
        # dist[x] = minimum cost to reach x (sum of all values taken including x)
        dist = {n: n}
        heap = [(n, n)]  # (current_cost, current_number)

        while heap:
            cost, u = heapq.heappop(heap)

            # Skip if we've already found a better path
            if cost != dist[u]:
                continue

            # Found target
            if u == m:
                return cost

            # Generate neighbors by changing one digit
            s = list(str(u))
            for i in range(d):
                digit = int(s[i])

                # Try increase digit
                if digit < 9:
                    s[i] = str(digit + 1)
                    v = int(''.join(s))
                    if not is_prime[v]:
                        new_cost = cost + v
                        if v not in dist or new_cost < dist[v]:
                            dist[v] = new_cost
                            heapq.heappush(heap, (new_cost, v))
                    s[i] = str(digit)  # restore

                # Try decrease digit
                if digit > 0:
                    # Skip if this is the first digit and would become 0 (leading zero)
                    if i == 0 and digit == 1:
                        continue
                    s[i] = str(digit - 1)
                    v = int(''.join(s))
                    if not is_prime[v]:
                        new_cost = cost + v
                        if v not in dist or new_cost < dist[v]:
                            dist[v] = new_cost
                            heapq.heappush(heap, (new_cost, v))
                    s[i] = str(digit)  # restore

        return -1

