class Solution:
    def countComponents(self, nums: List[int], threshold: int) -> int:
        # Filter numbers that can potentially be connected (<= threshold)
        # Numbers > threshold are isolated since lcm(x, y) >= x > threshold for any y
        relevant = [x for x in nums if x <= threshold]
        isolated_count = len(nums) - len(relevant)

        if not relevant:
            return isolated_count

        # Map values to indices for DSU
        val_to_idx = {val: i for i, val in enumerate(relevant)}
        m = len(relevant)

        # DSU initialization
        parent = list(range(m))
        rank = [0] * m

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            px, py = find(x), find(y)
            if px == py:
                return
            if rank[px] < rank[py]:
                px, py = py, px
            parent[py] = px
            if rank[px] == rank[py]:
                rank[px] += 1

        # For each multiple L, store the index of the first number that divides L
        first = [-1] * (threshold + 1)

        # For each number, mark its multiples
        # Two numbers a and b are connected if they share a common multiple L <= threshold
        # (meaning lcm(a,b) <= threshold)
        for val in relevant:
            idx = val_to_idx[val]
            # iterate through all multiples of val up to threshold
            for mult in range(val, threshold + 1, val):
                if first[mult] == -1:
                    first[mult] = idx
                else:
                    union(idx, first[mult])

        # Count unique components among relevant numbers
        unique_roots = set()
        for i in range(m):
            unique_roots.add(find(i))

        return len(unique_roots) + isolated_count

