class Solution:
    def makeStringGood(self, s: str) -> int:
        # Count frequencies
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - ord('a')] += 1

        n = len(s)
        INF = float('inf')

        # Generate candidate values for k (target frequency)
        # k is of the form ceil(sum / m) or floor(sum / m) for interval sums and m=1..26
        candidates = set()
        candidates.add(1)
        candidates.add(n)

        for l in range(26):
            cur_sum = 0
            for r in range(l, 26):
                cur_sum += cnt[r]
                if cur_sum == 0:
                    continue
                for m in range(1, 27):
                    # floor
                    k = cur_sum // m
                    if 1 <= k <= n:
                        candidates.add(k)
                    # ceil
                    k = (cur_sum + m - 1) // m
                    if 1 <= k <= n:
                        candidates.add(k)

        ans = INF

        # Try each candidate k
        for k in candidates:
            # dp: dict mapping incoming_flow -> min_cost
            dp = {0: 0}
            for i in range(26):
                new_dp = {}
                c = cnt[i]
                is_last = (i == 25)
                for f, cost in dp.items():
                    s = f + c

                    # Option 1: do not keep character i
                    if is_last:
                        nf = 0
                    else:
                        nf = s
                    nc = cost + s
                    if nf in new_dp:
                        if nc < new_dp[nf]:
                            new_dp[nf] = nc
                    else:
                        new_dp[nf] = nc

                    # Option 2: keep character i (contributes to good string with freq k)
                    if s >= k:
                        nf = s - k
                        add = s - k
                    else:
                        nf = 0
                        add = k - s

                    if is_last:
                        nf = 0

                    nc = cost + add
                    if nf in new_dp:
                        if nc < new_dp[nf]:
                            new_dp[nf] = nc
                    else:
                        new_dp[nf] = nc

                dp = new_dp
                if not dp:
                    break

            if dp and 0 in dp:
                if dp[0] < ans:
                    ans = dp[0]

        # Edge case: try k up to max frequency or n
        # The candidates should cover it, but ensure we have reasonable answer
        if ans == INF:
            # Fallback: try small range of k
            for k in range(1, min(n+1, 1000)):
                dp = {0: 0}
                for i in range(26):
                    new_dp = {}
                    for f, cost in dp.items():
                        s = f + cnt[i]
                        # Not keep
                        nf = 0 if i == 25 else s
                        nc = cost + s
                        if nf not in new_dp or nc < new_dp[nf]:
                            new_dp[nf] = nc
                        # Keep
                        if s >= k:
                            nf2 = 0 if i == 25 else s - k
                            nc2 = cost + s - k
                        else:
                            nf2 = 0
                            nc2 = cost + k - s
                        if nf2 not in new_dp or nc2 < new_dp[nf2]:
                            new_dp[nf2] = nc2
                    dp = new_dp
                if 0 in dp:
                    ans = min(ans, dp[0])

        return ans

