class Solution:
    def minLength(self, s: str, numOps: int) -> int:
        n = len(s)
        if n <= 1:
            return n

        # Identify runs of consecutive identical characters
        runs = []
        curr_len = 1
        for i in range(1, n):
            if s[i] == s[i-1]:
                curr_len += 1
            else:
                runs.append(curr_len)
                curr_len = 1
        runs.append(curr_len)

        # Binary search on the answer (minimum possible max run length)
        low, high = 1, n

        def is_possible(k):
            """Check if we can achieve max run length <= k with at most numOps operations"""
            if k <= 0:
                return False
            ops_needed = 0
            # To break a run of length L into segments of size at most k, 
            # we need L // (k + 1) operations
            for length in runs:
                ops_needed += length // (k + 1)
                if ops_needed > numOps:
                    return False
            return ops_needed <= numOps

        while low < high:
            mid = (low + high) // 2
            if is_possible(mid):
                high = mid
            else:
                low = mid + 1

        return low

class Solution:
    def answerString(self, word: str, numFriends: int) -> str:
        # If there's only 1 friend, the only possible split is the word itself
        if numFriends == 1:
            return word

        n = len(word)
        # Maximum length of any part in a split into numFriends parts
        # n - numFriends + 1 = max length of a substring that can be one of the parts
        max_len = n - numFriends + 1

        res = ""
        # Check all possible starting positions
        for i in range(n):
            # From position i, the part can extend at most max_len characters,
            # or until the end of the string
            end = min(i + max_len, n)
            curr = word[i:end]
            # Update result if current substring is lexicographically larger
            if curr > res:
                res = curr

        return res

