from typing import List

class Fenwick:
    def __init__(self, size):
        self.n = size
        self.tree = [0] * (size + 1)

    def add(self, idx, delta):
        idx += 1  # 1-indexed
        while idx <= self.n:
            self.tree[idx] += delta
            idx += idx & -idx

    def query(self, idx):
        # Sum of [0..idx]
        if idx < 0:
            return 0
        idx += 1
        res = 0
        while idx > 0:
            res += self.tree[idx]
            idx -= idx & -idx
        return res

    def range_query(self, l, r):
        if l > r:
            return 0
        return self.query(r) - self.query(l - 1)

class Solution:
    def numberOfSubsequences(self, nums: List[int]) -> int:
        n = len(nums)
        product_pairs = defaultdict(list)

        # Generate all pairs (i, j) where j - i >= 4
        # This ensures room for the middle elements with required gaps
        for i in range(n):
            for j in range(i + 4, n):
                prod = nums[i] * nums[j]
                product_pairs[prod].append((i, j))

        ans = 0

        for prod, pairs in product_pairs.items():
            # Sort by the first element (p or q)
            pairs.sort()
            k = len(pairs)

            # Fenwick tree to count occurrences of r values
            bit = Fenwick(n)

            j = 0
            # Iterate through each pair as (q, s)
            for i in range(k):
                q, s = pairs[i]

                # Add all pairs (p, r) with p <= q - 2 to the BIT
                while j < k and pairs[j][0] <= q - 2:
                    r = pairs[j][1]
                    bit.add(r, 1)
                    j += 1

                # Query for r in [q + 2, s - 2]
                # This ensures: r >= q + 2 (gap between q and r)
                # and r <= s - 2 (gap between r and s)
                left_bound = q + 2
                right_bound = s - 2

                if left_bound <= right_bound:
                    ans += bit.range_query(left_bound, right_bound)

        return ans

from typing import List

class Solution:
    def countSubarrays(self, nums: List[int]) -> int:
        count = 0
        n = len(nums)
        # Iterate over all starting positions of subarrays of length 3
        for i in range(n - 2):
            # Check if first + third equals half of the second
            # i.e., 2*(nums[i] + nums[i+2]) == nums[i+1]
            if 2 * (nums[i] + nums[i+2]) == nums[i+1]:
                count += 1
        return count

from typing import List

class Solution:
    def countPathsWithXorValue(self, grid: List[List[int]], k: int) -> int:
        MOD = 10**9 + 7
        m = len(grid)
        n = len(grid[0])

        # prev[j][x] – dp for cell (i-1, j)
        prev = [[0] * 16 for _ in range(n)]

        for i in range(m):
            cur = [[0] * 16 for _ in range(n)]
            for j in range(n):
                val = grid[i][j]
                if i == 0 and j == 0:
                    # start cell
                    cur[j][val] = 1
                    continue

                cur_j = cur[j]          # local reference for speed
                # paths coming from the top (i-1, j)
                if i > 0:
                    top = prev[j]
                    for x in range(16):
                        cnt = top[x]
                        if cnt:
                            nxt = x ^ val
                            cur_j[nxt] = (cur_j[nxt] + cnt) % MOD
                # paths coming from the left (i, j-1)
                if j > 0:
                    left = cur[j - 1]
                    for x in range(16):
                        cnt = left[x]
                        if cnt:
                            nxt = x ^ val
                            cur_j[nxt] = (cur_j[nxt] + cnt) % MOD
            prev = cur   # move to next row

        return prev[n - 1][k] % MOD
